// Собираем diff из всех файлов PR
const files = $input.all().map(i => i.json);
const meta = $('Extract PR Metadata').first().json;

let diffText = '';
let fileCount = 0;

for (const file of files) {
  if (file.patch) {
    diffText += `\n### File: ${file.filename} (${file.status})\n`;
    diffText += '```diff\n' + file.patch + '\n```\n';
    fileCount++;
  }
}

// Ограничиваем размер diff (OpenAI имеет лимит токенов)
const MAX_CHARS = 12000;
if (diffText.length > MAX_CHARS) {
  diffText = diffText.substring(0, MAX_CHARS) + '\n\n... (diff обрезан из-за большого размера)';
}

return [{
  json: {
    diff: diffText,
    fileCount: fileCount,
    prTitle: meta.prTitle,
    prNumber: meta.prNumber,
    prAuthor: meta.prAuthor,
    repoFullName: meta.repoFullName
  }
}];

// Сохраняем PR-метаданные и передаём дальше
const body = $input.first().json.body;
return [{
  json: {
    prNumber: body.number,
    prTitle: body.pull_request.title,
    prAuthor: body.pull_request.user.login,
    repoFullName: body.repository.full_name
  }
}];

const reviewText = $input.first().json.output[0].content[0].text
return [{
  json: {
    body: "🤖 **AI Code Review** (автоматическое ревью)\n\n" + reviewText
    }
}];

const crypto = require('crypto');

  const appId = '3226690';
  const privateKey = `***`;

  const now = Math.floor(Date.now() / 1000);
  const payload = {
    iat: now - 60,
    exp: now + (10 * 60),
    iss: appId
  };

  // Кодируем header и payload в base64url
  function base64url(obj) {
    return Buffer.from(JSON.stringify(obj))
      .toString('base64')
      .replace(/=/g, '')
      .replace(/\+/g, '-')
      .replace(/\//g, '_');
  }

  const header = base64url({ alg: 'RS256', typ: 'JWT' });
  const body = base64url(payload);
  const signature = crypto
    .createSign('RSA-SHA256')
    .update(`${header}.${body}`)
    .sign(privateKey, 'base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');

  const jwt = `${header}.${body}.${signature}`;

  return [{ json: { jwt } }];
